1	// --- Rates, fees, and thresholds ---
2	const PROCESSING_FEE = 5;
3	const FIRST_INSURANCE_RATE = 0.1;
4	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
5	const LOYALTY_RATE = 0.2;
6	const LOYALTY_THRESHOLD_YEARS = 2;
7	const CURSE_RATE = 0.5;
8	const HIGH_ENCHANTMENT_RATE = 0.3;
9	const HIGH_ENCHANTMENT_THRESHOLD = 5;
10	const BLOCK_SIZE = 3;
11	const BLOCK_BASE_PREMIUM = 60;
12	const DEDUCTIBLE = 100;
13	const CAP_MULTIPLIER = 2;
14	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
15	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
16	
17	// --- Item catalog ---
18	const BASE_PREMIUM: Record<string, number> = {
19	  sword: 100,
20	  amulet: 60,
21	  staff: 80,
22	  potion: 40,
23	  rune: 25,
24	  moonstone: 25,
25	};
26	
27	const INSURANCE_VALUE: Record<string, number> = {
28	  sword: 1000,
29	  amulet: 600,
30	  staff: 800,
31	  potion: 400,
32	  rune: 250,
33	  moonstone: 250,
34	};
35	
36	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
37	
38	// --- Domain types ---
39	type Customer = { yearsWithMHPCO: number };
40	type Item = { type: string; cursed?: boolean; enchantment?: number; material?: string };
41	type QuoteStep = { op: "quote"; items: Item[] };
42	type Damage = { itemType: string; amount: number };
43	type Incident = { cause: string; damages: Damage[] };
44	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
45	type Step = QuoteStep | ClaimStep;
46	type Input = { customer: Customer; steps: Step[] };
47	type QuoteResult = { premium: number };
48	type ClaimResult = { payout: number; remainingCap: number };
49	type StepResult = QuoteResult | ClaimResult;
50	
51	const countByType = (items: Item[]): Map<string, number> => {
52	  const counts = new Map<string, number>();
53	  for (const item of items) {
54	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
55	  }
56	  return counts;
57	};
58	
59	const basePremiumForType = (type: string, count: number): number => {
60	  const unit = BASE_PREMIUM[type];
61	  if (COMPONENT_TYPES.has(type) && count === BLOCK_SIZE) {
62	    return BLOCK_BASE_PREMIUM;
63	  }
64	  return unit * count;
65	};
66	
67	const basePremium = (items: Item[]): number =>
68	  Array.from(countByType(items)).reduce(
69	    (total, [type, count]) => total + basePremiumForType(type, count),
70	    0,
71	  );
72	
73	// MHPCO always rounds premiums in its own favor (up).
74	const roundUpInMHPCOFavor = (amount: number): number => Math.ceil(amount);
75	
76	const isCursed = (item: Item): boolean => item.cursed === true;
77	const isHighlyEnchanted = (item: Item): boolean =>
78	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
79	
80	const itemSurcharge = (item: Item): number => {
81	  const unit = BASE_PREMIUM[item.type];
82	  const curseSurcharge = isCursed(item) ? unit * CURSE_RATE : 0;
83	  const enchantmentSurcharge = isHighlyEnchanted(item)
84	    ? unit * HIGH_ENCHANTMENT_RATE
85	    : 0;
86	  return curseSurcharge + enchantmentSurcharge;
87	};
88	
89	const sumItemSurcharges = (items: Item[]): number =>
90	  items.reduce((total, item) => total + itemSurcharge(item), 0);
91	
92	const isLoyalCustomer = (customer: Customer): boolean =>
93	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS;
94	
95	const loyaltyDiscount = (base: number, customer: Customer): number =>
96	  isLoyalCustomer(customer) ? base * LOYALTY_RATE : 0;
97	
98	const firstInsuranceSurcharge = (base: number): number =>
99	  base * FIRST_INSURANCE_RATE;
100	
101	const followUpDiscount = (base: number, stepIndex: number): number =>
102	  stepIndex > 0 ? base * FOLLOW_UP_DISCOUNT_RATE : 0;
103	
104	const quotePremium = (
105	  { items }: QuoteStep,
106	  customer: Customer,
107	  stepIndex: number,
108	): QuoteResult => {
109	  const base = basePremium(items);
110	  const premium =
111	    base +
112	    sumItemSurcharges(items) +
113	    firstInsuranceSurcharge(base) -
114	    loyaltyDiscount(base, customer) -
115	    followUpDiscount(base, stepIndex) +
116	    PROCESSING_FEE;
117	  return { premium: roundUpInMHPCOFavor(premium) };
118	};
119	
120	const insuranceSum = (items: Item[]): number =>
121	  items.reduce((total, item) => total + INSURANCE_VALUE[item.type], 0);
122	
123	const policyCap = (items: Item[]): number =>
124	  CAP_MULTIPLIER * insuranceSum(items);
125	
126	const reimbursableAmount = (item: Item, amount: number): number =>
127	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD
128	    ? amount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
129	    : amount;
130	
131	const damagePayout = (damage: Damage, items: Item[]): number => {
132	  const item = items.find((i) => i.type === damage.itemType)!;
133	  return Math.max(reimbursableAmount(item, damage.amount) - DEDUCTIBLE, 0);
134	};
135	
136	const totalPayout = (damages: Damage[], items: Item[]): number =>
137	  damages.reduce((total, damage) => total + damagePayout(damage, items), 0);
138	
139	const processClaim = (step: ClaimStep, steps: Step[]): ClaimResult => {
140	  const policyStep = steps[step.policy] as QuoteStep;
141	  const payout = totalPayout(step.incident.damages, policyStep.items);
142	  return { payout, remainingCap: policyCap(policyStep.items) - payout };
143	};
144	
145	const processStep = (step: Step, index: number, steps: Step[], customer: Customer): StepResult =>
146	  step.op === "quote"
147	    ? quotePremium(step, customer, index)
148	    : processClaim(step, steps);
149	
150	export const run = (input: Input): { results: StepResult[] } => ({
151	  results: input.steps.map((step, index) =>
152	    processStep(step, index, input.steps, input.customer),
153	  ),
154	});
